-- ============================================================================
-- Quiz Seed: Leviticus — Part 2 (Chapters 11–20)
-- 3 difficulties × 10 chapters = 160 total questions
--   kids:   3 per chapter  = 30
--   teens:  5 per chapter  = 50
--   adults: 8 per chapter  = 80
-- ============================================================================

-- ═══ Leviticus Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 11, 'kids', 1, 'What two things must an animal have to be clean and safe to eat?', 'Wings and feathers', 'Split hooves and chewing the cud', 'Fins and scales', 'Four legs and a tail', 'a', 'Leviticus 11:3 — "Whatsoever parteth the hoof, and is clovenfooted, and cheweth the cud, among the beasts, that shall ye eat."'),
('Leviticus', 11, 'kids', 2, 'Is the pig a clean or unclean animal according to these rules?', 'Unclean', 'Clean', 'It depends on how it is cooked', 'Clean only in winter', 'a', 'Leviticus 11:7 — "And the swine, though he divide the hoof, and be clovenfooted, yet he cheweth not the cud; he is unclean to you."'),
('Leviticus', 11, 'kids', 3, 'What two things must a water creature have to be eaten?', 'Fins and scales', 'Gills and a tail', 'A hard shell and legs', 'Bright colours and a big body', 'a', 'Leviticus 11:9 — "These shall ye eat of all that are in the waters: whatsoever hath fins and scales in the waters...that shall ye eat."'),
-- Teens
('Leviticus', 11, 'teens', 1, 'The camel chews the cud but does not have split hooves. What does this make it according to Leviticus 11?', 'Clean to eat', 'Unclean to eat', 'Acceptable only as a sacrifice', 'Clean but only in certain seasons', 'a', 'Leviticus 11:4 — "Nevertheless these shall ye not eat of them that chew the cud, or of them that divide the hoof: as the camel, because he cheweth the cud, but divideth not the hoof; he is unclean unto you."'),
('Leviticus', 11, 'teens', 2, 'What made the eagle unclean according to Leviticus 11?', 'It was listed among the abominable birds', 'It ate carrion and other birds', 'It had no feathers on its legs', 'It could not be caught', 'a', 'Leviticus 11:13 — "And these are they which ye shall have in abomination among the fowls; they shall not be eaten, they are an abomination: the eagle..."'),
('Leviticus', 11, 'teens', 3, 'Which creeping things were permitted for eating?', 'Locusts, bald locust, beetle, and grasshopper', 'Ants, beetles, and spiders', 'Worms and caterpillars', 'All creeping things in the field', 'a', 'Leviticus 11:22 — "Even these of them ye may eat; the locust after his kind, and the bald locust after his kind, and the beetle after his kind, and the grasshopper after his kind."'),
('Leviticus', 11, 'teens', 4, 'What was the consequence of touching the dead body of an unclean animal?', 'The person was put to death', 'The person was unclean until evening', 'The person had to offer a burnt offering', 'The person had to leave the camp for seven days', 'a', 'Leviticus 11:24 — "And for these ye shall be unclean: whosoever toucheth the carcase of them shall be unclean until the even."'),
('Leviticus', 11, 'teens', 5, 'What reason does God give for the Israelites needing to be holy in their diet?', 'Because they were stronger than other nations', 'Because God is holy and had separated them from other peoples', 'Because the other foods would make them sick', 'Because Moses commanded it from his own wisdom', 'a', 'Leviticus 11:44 — "For I am the LORD your God: ye shall therefore sanctify yourselves, and ye shall be holy; for I am holy."'),
-- Adults
('Leviticus', 11, 'adults', 1, 'What term does Leviticus 11 repeatedly use for forbidden animals, emphasising their ritual status?', 'Unworthy', 'Abomination', 'Corrupt', 'Defiled', 'a', 'Leviticus 11:10 — "But all that have not fins and scales in the seas, and in the rivers, of all that move in the waters...they shall be an abomination unto you."'),
('Leviticus', 11, 'adults', 2, 'The hyrax (coney) is listed as unclean. What is the reason given?', 'It has no hooves at all', 'It chews the cud but does not divide the hoof', 'It divides the hoof but does not chew the cud', 'It is a burrowing creature', 'a', 'Leviticus 11:5 — "And the coney, because he cheweth the cud, but divideth not the hoof; he is unclean unto you."'),
('Leviticus', 11, 'adults', 3, 'What category of unclean creature includes the gecko, monitor lizard, and lizard?', 'Fowls of the air', 'The weasel and mouse class', 'Creeping things that creep upon the earth', 'Things that swarm the water', 'a', 'Leviticus 11:29-30 — "These also shall be unclean unto you among the creeping things that creep upon the earth; the weasel, and the mouse, and the tortoise after his kind, and the ferret, and the chameleon..."'),
('Leviticus', 11, 'adults', 4, 'What happens to a clay vessel into which a carcass of an unclean creature falls?', 'It must be washed and dried', 'It shall be broken', 'It must be buried outside the camp', 'It must be passed through fire', 'a', 'Leviticus 11:33 — "And every earthen vessel, whereinto any of them falleth, whatsoever is in it shall be unclean; and ye shall break it."'),
('Leviticus', 11, 'adults', 5, 'If a clean animal dies of itself and a man eats of it, what must he do?', 'Offer a guilt offering immediately', 'Wash his clothes, be unclean until even, and then be clean', 'He must be put to death', 'He must leave the community for seven days', 'a', 'Leviticus 11:40 — "And he that eateth of the carcase of it shall wash his clothes, and be unclean until the even: he also that beareth the carcase of it shall wash his clothes, and be unclean until the even."'),
('Leviticus', 11, 'adults', 6, 'How does Peter''s vision in Acts 10 relate theologically to Leviticus 11?', 'Peter was reminded to keep the food laws strictly', 'God declared all foods clean, signifying the inclusion of Gentiles in the covenant', 'Peter was taught new dietary rules for the church', 'The vision had nothing to do with Leviticus 11', 'a', 'Acts 10:15 — "What God hath cleansed, that call not thou common." This vision echoes Leviticus 11 food distinctions and points to the breaking down of barriers between Jew and Gentile.'),
('Leviticus', 11, 'adults', 7, 'The four-fold phrase "I am the LORD your God" appears as the basis for holiness. What does this reveal about the nature of Israel''s dietary laws?', 'They were merely hygienic rules for desert survival', 'They were covenant obligations rooted in the character and holiness of God', 'They were temporary until the monarchy was established', 'They were borrowed from surrounding cultures', 'a', 'Leviticus 11:44 — "For I am the LORD your God: ye shall therefore sanctify yourselves, and ye shall be holy; for I am holy." The laws reflect God''s own character as their foundation.'),
('Leviticus', 11, 'adults', 8, 'What is the significance of the phrase "among all manner of beasts that are on the earth" at the end of Leviticus 11?', 'It limits the laws to domesticated animals only', 'It extends the scope of these holiness distinctions to every creature on earth', 'It is a summary before a new legal code begins', 'It is a doxology praising God as Creator', 'a', 'Leviticus 11:46 — "This is the law of the beasts, and of the fowl, and of every living creature that moveth in the waters, and of every creature that creepeth upon the earth." The summary statement establishes the comprehensive scope of the clean/unclean distinctions.');

-- ═══ Leviticus Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 12, 'kids', 1, 'How many days was a woman considered unclean after giving birth to a boy?', '7 days', '14 days', '40 days', '30 days', 'a', 'Leviticus 12:2 — "If a woman have conceived seed, and born a man child: then she shall be unclean seven days."'),
('Leviticus', 12, 'kids', 2, 'What happened to a baby boy on the eighth day after he was born?', 'He was brought to the tabernacle', 'He was circumcised', 'He was given a name by the priest', 'He was washed in the river', 'a', 'Leviticus 12:3 — "And in the eighth day the flesh of his foreskin shall be circumcised."'),
('Leviticus', 12, 'kids', 3, 'What offering could a poor mother bring instead of a lamb?', 'Two doves or two young pigeons', 'A handful of flour', 'A jar of oil', 'A small goat', 'a', 'Leviticus 12:8 — "And if she be not able to bring a lamb, then she shall bring two turtles, or two young pigeons; the one for the burnt offering, and the other for a sin offering."'),
-- Teens
('Leviticus', 12, 'teens', 1, 'How long was the total purification period after the birth of a son?', '7 days', '33 days of purification after the initial 7', '40 days total', 'Both B and C are correct', 'a', 'Leviticus 12:4 — "And she shall then continue in the blood of her purifying three and thirty days." The 7 days plus 33 days makes 40 days total, but the 33 days are specifically called the blood of her purifying.'),
('Leviticus', 12, 'teens', 2, 'How did the purification period differ when a daughter was born?', 'It was the same as for a son', 'It was doubled — 14 days unclean and 66 days of purification', 'It was halved', 'Only the father needed purification', 'a', 'Leviticus 12:5 — "But if she bear a maid child, then she shall be unclean two weeks...and she shall continue in the blood of her purifying threescore and six days."'),
('Leviticus', 12, 'teens', 3, 'What were the two offerings a mother was to bring at the end of her purification?', 'A burnt offering and a sin offering', 'A peace offering and a burnt offering', 'A trespass offering and a sin offering', 'A grain offering and a drink offering', 'a', 'Leviticus 12:6 — "She shall bring a lamb of the first year for a burnt offering, and a young pigeon, or a turtledove, for a sin offering."'),
('Leviticus', 12, 'teens', 4, 'To whom were the purification offerings presented after childbirth?', 'The elders of Israel', 'The priest at the door of the tabernacle', 'The father of the child', 'The Levites at the gate', 'a', 'Leviticus 12:6 — "She shall bring them unto the priest, unto the door of the tabernacle of the congregation."'),
('Leviticus', 12, 'teens', 5, 'How does the offering made by Mary after Jesus'' birth in Luke 2:24 connect to Leviticus 12?', 'Mary did not follow the law of Moses', 'Mary offered two turtledoves, the provision for the poor given in Leviticus 12:8', 'Mary offered a lamb because she was wealthy', 'Mary''s offering was a new type not in the law', 'a', 'Luke 2:24 — "A pair of turtledoves, or two young pigeons" — fulfilling the poor woman''s provision of Leviticus 12:8, indicating the humble circumstances of Jesus'' family.'),
-- Adults
('Leviticus', 12, 'adults', 1, 'What is the theological reason scholars suggest for the doubled purification period after the birth of a daughter?', 'Girls are considered less holy than boys', 'The birth of a female doubled the potential for future uncleanness through childbirth cycles', 'God showed favoritism toward male children', 'The law was cultural and had no theological meaning', 'a', 'Leviticus 12:5 — The doubling of the purification period for a daughter has been interpreted as relating to the additional dimension of the daughter herself being a future bearer of the uncleanness associated with birth, though the text does not make this explicit.'),
('Leviticus', 12, 'adults', 2, 'What is the significance of the circumcision occurring on the eighth day within the broader legal framework?', 'Eight was the favourite number of Moses', 'The eighth day falls after the initial seven-day period of uncleanness, placing circumcision at the dawn of renewed cleanness', 'It had no significance beyond tradition', 'It matched Egyptian calendar customs', 'a', 'Leviticus 12:2-3 — The seven days of uncleanness end, and on the eighth day circumcision takes place, symbolically connecting the child to the covenant at the threshold of a new period.'),
('Leviticus', 12, 'adults', 3, 'What Hebrew concept does the word "purifying" (tohorot) in Leviticus 12 relate to in the broader law of uncleanness?', 'Moral guilt requiring atonement', 'Ritual impurity that disqualified one from sacred spaces, not a moral failing', 'Physical disease needing medical treatment', 'Social exclusion as a form of punishment', 'a', 'The purification laws of Leviticus 12 involve ritual impurity (tum''ah), not moral sin. The offerings restore the mother to the full ritual life of the community, not to moral standing she had lost.'),
('Leviticus', 12, 'adults', 4, 'What does the phrase "atonement for her" in Leviticus 12:8 imply about the sin offering made after childbirth?', 'The mother had sinned in giving birth', 'The sin offering functioned ritually to restore the mother to the holy community, marking the end of her period of separation', 'The midwife had committed a sin', 'The child was being dedicated to God', 'a', 'Leviticus 12:8 — "And the priest shall make an atonement for her, and she shall be clean." The sin offering here is not for moral transgression but for ritual restoration to the sacred community.'),
('Leviticus', 12, 'adults', 5, 'What parallel exists between the forty-day purification after a son''s birth and other significant forty-day periods in Scripture?', 'There is no parallel — it is simply a number', 'Forty days recalls the flood, Moses on Sinai, and Jesus'' temptation — a period of transition and renewal', 'Forty days matches a lunar month cycle', 'It was based on the time needed for wounds to heal', 'a', 'The 40 days total for a son (7+33, Leviticus 12:2-4) echo the biblical pattern of forty as a period of testing, transition, and new beginning found throughout Scripture (Genesis 7:4; Exodus 34:28; Luke 4:2).'),
('Leviticus', 12, 'adults', 6, 'How does Leviticus 12 reflect the broader principle of holiness distinctions between common and holy in Leviticus?', 'It isolates mothers as sinners', 'It shows that even natural biological processes create ritual states that must be resolved before returning to the holy community', 'It has no connection to the holiness theme', 'It only applies to the Levitical priesthood', 'a', 'Leviticus 12 is part of the Holiness Code''s systematic treatment of states that affect one''s access to sacred space, showing that even natural life events like childbirth interact with the boundary between holy and common.'),
('Leviticus', 12, 'adults', 7, 'The turtledove or pigeon option for the poor appears also in Leviticus 1:14. What does this provision reveal about the character of the Mosaic law?', 'The law was only for the wealthy', 'God''s mercy accommodated the economic circumstances of all Israel so none were excluded from worship', 'Poor people could avoid the law', 'The offerings were not really important to God', 'a', 'Leviticus 12:8 — "And if she be not able to bring a lamb, then she shall bring two turtles, or two young pigeons." This provision demonstrates that the law made worship accessible to all economic classes.'),
('Leviticus', 12, 'adults', 8, 'How does Luke 2:22 describe Mary''s visit to the temple, and what does it reveal about Jesus'' relationship to the law?', 'Jesus was circumcised at the temple, replacing Leviticus 12', 'Mary fulfilled the days of her purification according to the law of Moses, showing Jesus was born under the law', 'Mary was exempt from the law because Jesus was the Son of God', 'Luke does not reference Leviticus 12', 'a', 'Luke 2:22 — "And when the days of her purification according to the law of Moses were accomplished, they brought him to Jerusalem." This demonstrates that Jesus was born under the law (Galatians 4:4), subject to the same Levitical requirements as any Israelite.');

-- ═══ Leviticus Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 13, 'kids', 1, 'Who was in charge of checking people for leprosy in Israel?', 'The king', 'The priest', 'The elder of the city', 'The mother of the family', 'a', 'Leviticus 13:2 — "He shall be brought unto Aaron the priest, or unto one of his sons the priests."'),
('Leviticus', 13, 'kids', 2, 'What was a person with leprosy supposed to say to warn others they were coming near?', 'Stay away!', 'Unclean, unclean!', 'I am sick!', 'Do not touch me!', 'a', 'Leviticus 13:45 — "And the leper in whom the plague is, his clothes shall be rent, and his head bare, and he shall put a covering upon his upper lip, and shall cry, Unclean, unclean."'),
('Leviticus', 13, 'kids', 3, 'How long did the priest put a person aside when he was not sure if a skin mark was leprosy?', '3 days', '7 days', '14 days', '1 month', 'a', 'Leviticus 13:4 — "Then the priest shall shut up him that hath the plague seven days."'),
-- Teens
('Leviticus', 13, 'teens', 1, 'What were the three physical signs that the priest looked for to determine if a skin sore was leprosy?', 'Redness, swelling, and pain', 'A white hair in the sore, the sore appearing deeper than the skin, and a spreading of the plague', 'A blister, a hard skin, and a foul smell', 'Loss of hair, numbness, and discolouration', 'a', 'Leviticus 13:3 — "And the priest shall look on the plague in the skin of the flesh: and when the hair in the plague is turned white, and the plague in sight be deeper than the skin of his flesh, it is a plague of leprosy."'),
('Leviticus', 13, 'teens', 2, 'What happened if a person''s skin turned completely white all over?', 'They were declared unclean', 'They were declared clean', 'They had to offer a sin offering', 'They were sent outside the camp immediately', 'a', 'Leviticus 13:13 — "Then the priest shall consider: and, behold, if the leprosy have covered all his flesh, he shall pronounce him clean that hath the plague: it is all turned white: he is clean."'),
('Leviticus', 13, 'teens', 3, 'How did the law deal with leprosy found in a garment?', 'The garment was to be washed and dried', 'The priest examined it, quarantined it for seven days, and if spreading, burned it', 'It was sold outside the camp', 'It was buried in the ground', 'a', 'Leviticus 13:47-52 — The priest examined the garment, shut it up for seven days, re-examined it, and if the plague had spread, it was to be burnt with fire.'),
('Leviticus', 13, 'teens', 4, 'What had to happen to the clothing of a confirmed leper?', 'It had to be washed seven times', 'His clothes were to be torn', 'His clothes were to be burned', 'His clothes were given to the priest', 'a', 'Leviticus 13:45 — "And the leper in whom the plague is, his clothes shall be rent, and his head bare, and he shall put a covering upon his upper lip, and shall cry, Unclean, unclean."'),
('Leviticus', 13, 'teens', 5, 'Where was a confirmed leper required to live?', 'In a special house within the camp', 'Outside the camp, alone', 'In the priest''s courtyard for care', 'In the city of refuge', 'a', 'Leviticus 13:46 — "All the days wherein the plague shall be in him he shall be defiled; he is unclean: he shall dwell alone; without the camp shall his habitation be."'),
-- Adults
('Leviticus', 13, 'adults', 1, 'The Hebrew word translated "leprosy" (tsara''at) in Leviticus 13 likely refers to what range of conditions?', 'Only the specific disease Hansen''s disease (true leprosy)', 'A wide range of skin diseases, mould, and surface conditions, not limited to Hansen''s disease', 'Exclusively infectious diseases', 'Conditions caused by sin only', 'a', 'The Hebrew tsara''at covers a broad category of skin conditions (Leviticus 13:2-46), mould on garments (v.47-59), and later on houses (ch.14). Modern scholars do not equate it solely with Hansen''s disease.'),
('Leviticus', 13, 'adults', 2, 'The priest''s role in diagnosing leprosy was primarily what kind of function?', 'Medical — the priests were trained physicians', 'Ritual and legal — the priest declared the ritual status of the person, not a medical diagnosis', 'Moral — the priest determined if sin caused the disease', 'Political — the priest enforced public health laws', 'a', 'In Leviticus 13, the priest does not treat the disease but pronounces the person clean or unclean (vv. 3, 8, 11, etc.), a ritual/legal determination affecting the person''s access to the community and the sanctuary.'),
('Leviticus', 13, 'adults', 3, 'What was the significance of the leper tearing his clothes and leaving his head bare?', 'It was a sign of mourning, marking him as one ritually dead to the community', 'It was for comfort during illness', 'It was a signal to the priest to come examine him', 'It was a form of self-punishment for sin', 'a', 'Leviticus 13:45 — The torn clothes and uncovered head mirror signs of mourning (Leviticus 10:6; Ezekiel 24:17), symbolising that the leper was ritually separated from the living community, as one in a state akin to death.'),
('Leviticus', 13, 'adults', 4, 'What is the theological significance of the leper dwelling "alone" outside the camp?', 'It was purely for hygiene and infection control', 'Uncleanness separated one from the holy community whose centre was the dwelling place of God', 'It was a punishment designed to shame the leper', 'The leper chose isolation voluntarily', 'a', 'Leviticus 13:46 — Separation from the camp is separation from the covenant community gathered around the tabernacle. Since God dwelt in the camp''s midst (Numbers 5:3), ritual uncleanness barred one from the holy presence.'),
('Leviticus', 13, 'adults', 5, 'How does Jesus'' healing of lepers in the New Testament interact with the Leviticus 13 framework?', 'Jesus ignored the Mosaic laws on leprosy entirely', 'Jesus healed lepers and then directed them to the priest for the prescribed Levitical examination and offering', 'Jesus declared the Levitical laws on leprosy abolished', 'Jesus treated lepers only after they were declared clean by the priest', 'a', 'Luke 17:14 — "And he said unto them, Go shew yourselves unto the priests." Jesus honoured the Levitical process while demonstrating divine authority to cleanse what the law could only diagnose, pointing to the fulfillment of the priestly examination.'),
('Leviticus', 13, 'adults', 6, 'What is the repeated phrase used by the priest when confirming leprosy, and what does it reflect about authority in the community?', '"The LORD has declared him unclean"', '"He is unclean: the priest shall pronounce him utterly unclean"', '"He shall go out from the camp forthwith"', '"His blood be upon his own head"', 'a', 'Leviticus 13:44 — "He is unclean: the priest shall pronounce him utterly unclean; his plague is in his head." The priest''s declaration carries legal force — it is the authoritative verdict that determines community status.'),
('Leviticus', 13, 'adults', 7, 'If a mark in a garment was found to have not spread after the second seven-day examination, what happened to the garment?', 'It was burned', 'The affected area was washed or torn out, and the garment declared clean or unclean depending on the result', 'It was given to the poor', 'It was buried outside the camp', 'a', 'Leviticus 13:55-58 — If the plague had not spread but not changed colour, it was to be washed; if the colour changed after washing, it was torn out. If the spot departed after washing, the garment was washed again and declared clean.'),
('Leviticus', 13, 'adults', 8, 'How does the concept of leprosy in Leviticus 13 function as a theological type or picture in Christian interpretation?', 'It has no typological significance', 'Leprosy has been understood as a type of sin — pervasive, defiling, separating one from God, and requiring divine cleansing rather than self-remedy', 'It only teaches public health principles', 'It is a type of the final judgment only', 'a', 'Leviticus 13:45-46 — The leper''s isolation, his cry of "Unclean, unclean," and the impossibility of self-cleansing have long been read as a picture of sin''s nature — spreading, separating, and requiring the priestly act of declaration and the grace of divine healing (cf. Isaiah 1:6; Luke 5:12-13).');

-- ═══ Leviticus Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 14, 'kids', 1, 'How many birds were used in the ceremony to cleanse a healed leper?', 'One', 'Two', 'Three', 'Four', 'a', 'Leviticus 14:4 — "Then shall the priest command to take for him that is to be cleansed two birds alive and clean."'),
('Leviticus', 14, 'kids', 2, 'What happened to the first bird in the leper''s cleansing ceremony?', 'It was set free', 'It was killed over running water', 'It was given to the priest', 'It was sent to the high priest', 'a', 'Leviticus 14:5 — "And the priest shall command that one of the birds be killed in an earthen vessel over running water."'),
('Leviticus', 14, 'kids', 3, 'What happened to the second live bird after being dipped in the blood of the first bird?', 'It was eaten by the priests', 'It was let loose in the open field', 'It was placed on the altar', 'It was given to the leper to keep', 'a', 'Leviticus 14:7 — "And he shall let the living bird loose into the open field."'),
-- Teens
('Leviticus', 14, 'teens', 1, 'Besides two birds, what other items were used in the initial cleansing of the leper outside the camp?', 'Cedar wood, scarlet thread, and hyssop', 'Oil, salt, and fine flour', 'Gold, silver, and bronze', 'Incense, myrrh, and aloes', 'a', 'Leviticus 14:4 — "Then shall the priest command to take for him that is to be cleansed two birds alive and clean, and cedar wood, and scarlet, and hyssop."'),
('Leviticus', 14, 'teens', 2, 'After the initial bird ceremony, how many days did the cleansed leper wait before shaving all his hair and washing before re-entering the camp?', '3 days', '7 days', '14 days', '40 days', 'a', 'Leviticus 14:8 — "And he that is to be cleansed shall wash his clothes, and shave off all his hair, and wash himself in water, that he may be clean: and after that he shall come into the camp, and shall tarry abroad out of his tent seven days."'),
('Leviticus', 14, 'teens', 3, 'On the eighth day of the leper''s cleansing, how many lambs, and what else, did a wealthy leper bring?', 'Two bulls and a ram', 'Three he-lambs, one ewe-lamb, fine flour, and oil', 'Two turtledoves and a lamb', 'One bull and seven lambs', 'a', 'Leviticus 14:10 — "And on the eighth day he shall take two he lambs without blemish, and one ewe lamb of the first year without blemish, and three tenth deals of fine flour for a meat offering, mingled with oil, and one log of oil."'),
('Leviticus', 14, 'teens', 4, 'What signs of leprosy in a house required the priest to be called?', 'A bad smell in the walls', 'Greenish or reddish streaks in the walls that appeared to be deeper than the surface', 'Cracks in the walls', 'Damp stones in the floor', 'a', 'Leviticus 14:37 — "And he shall look on the plague, and, behold, if the plague be in the walls of the house with hollow strakes, greenish or reddish, which in sight are lower than the wall."'),
('Leviticus', 14, 'teens', 5, 'If leprosy in a house spread after infected stones were removed and the house re-plastered, what happened to the house?', 'It was re-examined for another seven days', 'It was demolished and its materials carried out of the city', 'It was purified with hyssop and water', 'It was sold outside the city', 'a', 'Leviticus 14:45 — "And he shall break down the house, the stones of it, and the timber thereof, and all the mortar of the house; and he shall carry them forth out of the city into an unclean place."'),
-- Adults
('Leviticus', 14, 'adults', 1, 'The two-bird ceremony in Leviticus 14 closely parallels what other dual-animal rite in Leviticus?', 'The two bulls on the Day of Atonement', 'The two goats of Yom Kippur in Leviticus 16, with one slain and one released', 'The two turtledoves in Leviticus 12', 'The two rams of the ordination offering in Leviticus 8', 'a', 'Leviticus 14:4-7 — The parallel to Leviticus 16:7-22 is striking: one bird killed (death), one bird released bearing the blood of the first (bearing away), mirroring the slain goat and the scapegoat of the Day of Atonement.'),
('Leviticus', 14, 'adults', 2, 'What is the specific Hebrew unit of liquid measure used in the log of oil mentioned in Leviticus 14:10?', 'A bath', 'A hin', 'A log, the smallest liquid measure in the Mosaic system', 'A seah', 'a', 'Leviticus 14:10 — "one log of oil." The log (Hebrew: log) was the smallest liquid measure in the Old Testament system, approximately 300-500ml, used specifically in this unique purification rite.'),
('Leviticus', 14, 'adults', 3, 'The trespass offering (asham) in the leper''s cleansing is unique in Leviticus 14. What is exceptional about the application of its blood?', 'It was poured on the altar base only', 'Its blood was applied to the right ear, right thumb, and right big toe of the cleansed leper', 'It was sprinkled seven times before the veil', 'It was given to the priest to eat', 'a', 'Leviticus 14:14 — "And the priest shall take some of the blood of the trespass offering, and the priest shall put it upon the tip of the right ear of him that is to be cleansed, and upon the thumb of his right hand, and upon the great toe of his right foot." This mirrors the anointing of the priests in Leviticus 8:23.'),
('Leviticus', 14, 'adults', 4, 'The anointing of the ear, thumb, and great toe in Leviticus 14 echoes the consecration of Aaron and his sons in Leviticus 8. What theological point does this parallel make?', 'The leper was being ordained as a priest', 'Cleansing from leprosy was a form of re-consecration — a re-entry into the holy life of covenant service', 'It was a coincidence of ritual', 'The leper had to serve as a priest temporarily', 'a', 'By applying blood and oil to the same body points as in priestly ordination (Leviticus 8:23-24; 14:14-17), the text suggests that cleansing from leprosy was tantamount to being restored to full covenant standing — a re-consecration to life in God''s holy community.'),
('Leviticus', 14, 'adults', 5, 'In the cleansing rite, oil was first waved before the LORD and then applied. What does the wave offering of oil signify?', 'The oil was for burning', 'The oil was presented to God and then returned to the person as a mark of divine blessing and cleansing', 'The oil was given to the temple treasury', 'The waving purified the oil from contamination', 'a', 'Leviticus 14:24 — "And the priest shall take the lamb of the trespass offering, and the log of oil, and the priest shall wave them for a wave offering before the LORD." The wave offering acknowledged God''s ownership and the gift of cleansing flowing from Him.'),
('Leviticus', 14, 'adults', 6, 'What provision did the law make for a poor person who could not afford three lambs for the eighth-day offering?', 'They were permanently excluded from the community', 'One lamb as trespass offering plus two turtledoves or two pigeons for burnt and sin offerings', 'They could use grain only', 'The priest paid for the offering from the temple treasury', 'a', 'Leviticus 14:21-22 — "And if he be poor, and cannot get so much; then he shall take one lamb for a trespass offering to be waved, to make an atonement for him, and one tenth deal of fine flour mingled with oil...and two turtledoves, or two young pigeons."'),
('Leviticus', 14, 'adults', 7, 'When the priest declared the house clean after leprosy was cured, the same bird/cedar wood/hyssop ceremony was used. What is the significance of using the same rite for a person and a house?', 'It shows the law was applied inconsistently', 'The same categories of holy and unclean applied to persons, garments, and dwellings — the entire environment of covenant life needed to be maintained as clean', 'Houses could get true leprosy just like people', 'The ritual was reused to save time', 'a', 'Leviticus 14:49-53 — The identical purification ceremony for the house (cedar wood, scarlet, hyssop, two birds) as for the person (vv.4-7) shows that the holiness system governed all dimensions of Israelite life — body, clothing, and dwelling.'),
('Leviticus', 14, 'adults', 8, 'How does the priestly inspection of houses for leprosy in Leviticus 14:33-53 function in the context of Canaan''s conquest?', 'It was irrelevant since Israel had no houses yet', 'God gave this law before entering Canaan, anticipating the houses Israel would inherit, showing divine foreknowledge and providence', 'The law was added later by priests', 'It applied only to Levitical cities', 'a', 'Leviticus 14:34 — "When ye be come into the land of Canaan, which I give to you for a possession, and I put the plague of leprosy in a house of the land of your possession." The anticipatory nature of this law reveals God''s foreknowledge of the conquest and His concern to govern all aspects of Israel''s future life in the land.');

-- ═══ Leviticus Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 15, 'kids', 1, 'If a man with a bodily discharge sat on a bed or chair, what happened to those things?', 'Nothing happened to them', 'They became unclean', 'They were burned immediately', 'They had to be given to the priest', 'a', 'Leviticus 15:4 — "Every bed, whereon he lieth that hath the issue, is unclean: and every thing, whereon he sitteth, shall be unclean."'),
('Leviticus', 15, 'kids', 2, 'After a person with a discharge was healed, how many days did they wait before making offerings?', '3 days', '7 days', '14 days', '30 days', 'a', 'Leviticus 15:13 — "And when he that hath an issue is cleansed of his issue; then he shall number to himself seven days for his cleansing, and wash his clothes, and bathe his flesh in running water, and shall be clean."'),
('Leviticus', 15, 'kids', 3, 'What type of bird offerings were given to end the uncleanness from a discharge?', 'Two eagles', 'Two turtledoves or two young pigeons', 'Two sparrows', 'One dove and one lamb', 'a', 'Leviticus 15:14 — "And on the eighth day he shall take to him two turtledoves, or two young pigeons, and come before the LORD unto the door of the tabernacle of the congregation."'),
-- Teens
('Leviticus', 15, 'teens', 1, 'What was a person required to do who had touched someone with an issue or sat where they sat?', 'Bring a burnt offering immediately', 'Wash their clothes, bathe in water, and be unclean until evening', 'Leave the camp for seven days', 'Go to the priest for examination', 'a', 'Leviticus 15:7 — "And he that toucheth the flesh of him that hath the issue shall wash his clothes, and bathe himself in water, and be unclean until the even."'),
('Leviticus', 15, 'teens', 2, 'What made an unclean man''s bed or saddle used for riding defiling?', 'Any discharge that touched it', 'Anything he lay upon or sat upon, because of his uncleanness, defiled those who touched it', 'Only if the item was made of cloth', 'Only if he was sick for more than seven days', 'a', 'Leviticus 15:9-10 — "And what saddle soever he rideth upon that hath the issue shall be unclean. And whosoever toucheth any thing that was under him shall be unclean until the even."'),
('Leviticus', 15, 'teens', 3, 'What was the reason God gave at the end of chapter 15 for all these laws about bodily discharges?', 'To keep the Israelites physically healthy', 'So the people would not defile the tabernacle that God dwelt among them', 'To distinguish Israel from the Canaanites', 'So the priests would have work to do', 'a', 'Leviticus 15:31 — "Thus shall ye separate the children of Israel from their uncleanness; that they die not in their uncleanness, when they defile my tabernacle that is among them."'),
('Leviticus', 15, 'teens', 4, 'How long was a woman unclean during her regular monthly period according to Leviticus 15?', '3 days', '7 days', '14 days', 'Until she bathed', 'a', 'Leviticus 15:19 — "And if a woman have an issue, and her issue in her flesh be blood, she shall be put apart seven days: and whosoever toucheth her shall be unclean until the even."'),
('Leviticus', 15, 'teens', 5, 'What happened to a vessel or earthen pot touched by someone unclean from a discharge?', 'It had to be washed in the river', 'Any earthen vessel had to be broken, and a wooden vessel rinsed in water', 'It was buried outside the camp', 'Nothing, vessels were exempt', 'a', 'Leviticus 15:12 — "And the vessel of earth, that he toucheth which hath the issue, shall be broken: and every vessel of wood shall be rinsed in water."'),
-- Adults
('Leviticus', 15, 'adults', 1, 'Leviticus 15 distinguishes between what two types of male discharge?', 'Intentional and unintentional', 'Chronic running issue and a single emission of seed', 'Internal and external', 'Clean and unclean at the same time', 'a', 'Leviticus 15 covers a chronic "running issue" (vv.2-15) and a single emission of seed (vv.16-17), treating them with different levels of uncleanness: the chronic issue requiring full offering and seven-day cleansing, the single emission requiring only washing and waiting until evening.'),
('Leviticus', 15, 'adults', 2, 'How does Leviticus 15 treat the uncleanness of the woman with an abnormal discharge of blood beyond her regular cycle?', 'It is treated the same as regular menstruation', 'She is unclean for the duration of the discharge plus seven clean days after, requiring the same bird offerings as a man with an issue', 'She is permanently unclean and expelled from the camp', 'No special provision is made for her', 'a', 'Leviticus 15:25-30 — A woman with a running issue of blood beyond her regular period is unclean all the days of the discharge; after its cessation she counts seven days, then offers two turtledoves or two pigeons for a sin offering and burnt offering.'),
('Leviticus', 15, 'adults', 3, 'How does the woman with the issue of blood in Mark 5:25-34 relate to Leviticus 15?', 'She had broken no law since her disease was not addressed in Leviticus', 'She had been ritually unclean for twelve years under Leviticus 15:25 and would have made Jesus ritually unclean by touching Him — yet He healed her', 'She was exempt from the law because she was of the tribe of Judah', 'The connection is purely coincidental', 'a', 'Leviticus 15:25-27 states that anyone touching a woman with a running issue of blood would be unclean until evening. The woman in Mark 5:27 touched Jesus — yet instead of Jesus becoming unclean, cleansing flowed from Him to her, revealing His power over the ritual system.'),
('Leviticus', 15, 'adults', 4, 'What is the underlying theological principle that unites all the discharge laws of Leviticus 15?', 'Physical hygiene was the primary concern', 'The life force (blood, seed) belonged to God; its uncontrolled flow created a state of disorder requiring restoration', 'These laws were cultural taboos adopted from Egypt', 'The laws only applied to the priests', 'a', 'Leviticus 15 treats discharges involving blood and reproductive fluids with special seriousness because these were associated with life and death, which belonged uniquely to God (cf. Leviticus 17:11). Their uncontrolled flow signified a disorder that required ritual restoration.'),
('Leviticus', 15, 'adults', 5, 'The phrase "running water" for the cleansing of the chronic male discharge sufferer is significant. What does "running water" (mayim chayyim) mean in Hebrew?', 'Fast-moving river water', 'Living water — fresh, flowing water, symbolically associated with purification and life', 'Rainwater collected in a basin', 'Water blessed by the priest', 'a', 'Leviticus 15:13 — "running water" is mayim chayyim, literally "living waters." This term echoes Jeremiah 2:13 and John 4:10-14, where "living water" becomes a metaphor for divine cleansing and life.'),
('Leviticus', 15, 'adults', 6, 'What is unique about the fact that Leviticus 15 addresses both male and female bodily states with parallel structures?', 'The law was biased toward males', 'The parallel structure shows the law''s concern for ritual purity applied equally to both sexes, treating them with equal dignity before God''s holiness', 'Women''s uncleanness was considered more serious', 'The parallel is coincidental', 'a', 'Leviticus 15:1-15 (male issue) is paralleled by vv.25-30 (female issue), and vv.16-18 (male emission) by vv.19-24 (female cycle). The structural symmetry reflects the law''s comprehensive and impartial application to all Israel.'),
('Leviticus', 15, 'adults', 7, 'What does the death warning in Leviticus 15:31 — "that they die not in their uncleanness, when they defile my tabernacle" — reveal about the holiness of the tabernacle?', 'The tabernacle was merely a religious building', 'The tabernacle was the dwelling place of the holy God; uncleanness in God''s presence was lethal because holiness and impurity cannot coexist', 'The warning was exaggerated for effect', 'It refers only to the High Priest''s death', 'a', 'Leviticus 15:31 — "Thus shall ye separate the children of Israel from their uncleanness; that they die not in their uncleanness, when they defile my tabernacle that is among them." The tabernacle housed God''s glory; contact between radical holiness and impurity was fatal (cf. Leviticus 10:1-2; Numbers 4:19-20).'),
('Leviticus', 15, 'adults', 8, 'How do the purity laws of Leviticus 15 function missiologically — that is, what purpose did they serve in relation to surrounding nations?', 'They isolated Israel so it had no contact with other nations', 'They created a visible, bodily-embedded holiness ethic that marked Israel as a people governed by God''s order, testifying to the nations of a different way of life', 'They had no missiological purpose', 'They were borrowed from Babylonian purity codes', 'a', 'The bodily purity laws embedded holiness into the most intimate aspects of daily life, making Israel visibly distinct (cf. Leviticus 20:26 — "I have severed you from other people, that ye should be mine"). This distinctiveness served God''s purpose of displaying His character to the nations through His covenant people.');

-- ═══ Leviticus Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 16, 'kids', 1, 'What special day is described in Leviticus 16 when the high priest went into the most holy place?', 'The Passover', 'The Day of Atonement', 'The Feast of Tabernacles', 'The Feast of Firstfruits', 'a', 'Leviticus 16:30 — "For on that day shall the priest make an atonement for you, to cleanse you, that ye may be clean from all your sins before the LORD." This day is Yom Kippur, the Day of Atonement.'),
('Leviticus', 16, 'kids', 2, 'How many goats were used on the Day of Atonement?', 'One', 'Two', 'Three', 'Seven', 'a', 'Leviticus 16:7 — "And he shall take the two goats, and present them before the LORD at the door of the tabernacle of the congregation."'),
('Leviticus', 16, 'kids', 3, 'What did Aaron do with the live goat that was not sacrificed?', 'He released it in the wilderness', 'He sent it outside the camp bearing Israel''s sins', 'He gave it to the poor', 'He kept it for the next year', 'a', 'Leviticus 16:21-22 — "And Aaron shall lay both his hands upon the head of the live goat, and confess over him all the iniquities of the children of Israel...and shall send him away by the hand of a fit man into the wilderness."'),
-- Teens
('Leviticus', 16, 'teens', 1, 'Why was Aaron warned not to enter the Most Holy Place at just any time?', 'Because only the Levites could enter', 'Because God appeared in the cloud above the mercy seat and Aaron would die', 'Because the ark was too heavy to move aside', 'Because only the morning and evening were permitted times', 'a', 'Leviticus 16:2 — "And the LORD said unto Moses, Speak unto Aaron thy brother, that he come not at all times into the holy place within the vail before the mercy seat, which is upon the ark; that he die not: for I will appear in the cloud upon the mercy seat."'),
('Leviticus', 16, 'teens', 2, 'What did Aaron wear when he entered the Most Holy Place on the Day of Atonement?', 'His full high priestly garments with breastplate and ephod', 'Simple holy linen garments — coat, breeches, girdle, and mitre', 'The garments of a regular priest', 'Only a white robe with no other garment', 'a', 'Leviticus 16:4 — "He shall put on the holy linen coat, and he shall have the linen breeches upon his flesh, and shall be girded with a linen girdle, and with the linen mitre shall he be attired: these are holy garments; therefore shall he wash his flesh in water, and so put them on."'),
('Leviticus', 16, 'teens', 3, 'What did Aaron use to fill the Most Holy Place with a cloud before approaching the mercy seat?', 'Incense on a censer of fire taken from the altar', 'Burning wood from the altar', 'Oil poured on the mercy seat', 'Prayers offered at the door of the tabernacle', 'a', 'Leviticus 16:12-13 — "And he shall take a censer full of burning coals of fire from off the altar before the LORD, and his hands full of sweet incense beaten small, and bring it within the vail: and he shall put the incense upon the fire before the LORD, that the cloud of the incense may cover the mercy seat."'),
('Leviticus', 16, 'teens', 4, 'What was the name given to the goat sent into the wilderness bearing Israel''s sins?', 'The sacrificial goat', 'The scapegoat (Azazel)', 'The atonement goat', 'The wandering goat', 'a', 'Leviticus 16:8 — "And Aaron shall cast lots upon the two goats; one lot for the LORD, and the other lot for the scapegoat." The Hebrew is la-Azazel, rendered "scapegoat" in the KJV.'),
('Leviticus', 16, 'teens', 5, 'How often was the Day of Atonement to be observed?', 'Every month', 'Once a year, on the tenth day of the seventh month', 'Twice a year at the new moon', 'Only in years of Jubilee', 'a', 'Leviticus 16:29 — "And this shall be a statute for ever unto you: that in the seventh month, on the tenth day of the month, ye shall afflict your souls, and do no work at all."'),
-- Adults
('Leviticus', 16, 'adults', 1, 'The chapter opens with reference to the death of Aaron''s two sons. What is the theological function of this opening in Leviticus 16?', 'It is a historical aside', 'It establishes the danger of improper approach to God, motivating the precise regulations that follow for the Day of Atonement', 'It blames Aaron for their deaths', 'It introduces a new law about fire', 'a', 'Leviticus 16:1 — "And the LORD spake unto Moses after the death of the two sons of Aaron, when they offered before the LORD, and died." The deaths of Nadab and Abihu (Leviticus 10:1-2) frame the Day of Atonement laws as matters of life and death.'),
('Leviticus', 16, 'adults', 2, 'The Hebrew word Azazel in Leviticus 16:8 has been interpreted in several ways. What are the main scholarly interpretations?', 'Only as the name of a desert demon', 'As "complete removal" (the goal), a rocky cliff, or a desert demon — all pointing to permanent removal of sin from the community', 'Only as the name of the high priest who carried the goat', 'Only as the word for "wilderness"', 'a', 'Leviticus 16:8 — Azazel (Hebrew: la-Azazel) has been interpreted as: (1) "complete removal" or "entire sending away" of sin, (2) a specific desolate location, (3) a fallen angel/demon figure. All interpretations converge on the goat carrying sin to a place of permanent separation.'),
('Leviticus', 16, 'adults', 3, 'What does the double application of blood — first for Aaron and his household, then for the people — reveal about the Day of Atonement''s scope?', 'Only the people needed atonement, not the priests', 'Both priesthood and people needed atonement; even the mediator required cleansing before he could make atonement for others', 'Aaron made atonement for himself only as a formality', 'The double application doubled the effectiveness', 'a', 'Leviticus 16:11,15 — Aaron first sacrifices a bull for himself and his household (v.11), then a goat for the congregation (v.15). This shows that even the high priest was a sinner who needed atonement — a contrast to Hebrews 7:27 where Jesus "needeth not daily to offer up sacrifice, first for his own sins."'),
('Leviticus', 16, 'adults', 4, 'How does Hebrews 9 use Leviticus 16 to argue for the superiority of Christ''s atonement?', 'It argues that Leviticus 16 was completely unrelated to Christ', 'The annual, repeated entry of the high priest into the earthly Holy of Holies is contrasted with Christ''s once-for-all entry into heaven''s true sanctuary with His own blood', 'Hebrews 9 says the Day of Atonement never had any value', 'Hebrews 9 cites Leviticus 16 only as a historical record', 'a', 'Hebrews 9:7,12 — "But into the second went the high priest alone once every year, not without blood...But Christ being come an high priest...by his own blood he entered in once into the holy place, having obtained eternal redemption for us."'),
('Leviticus', 16, 'adults', 5, 'The mercy seat (kapporeth) in Leviticus 16 was where blood was sprinkled seven times. What is the etymological and theological significance of kapporeth?', 'It means "golden lid" referring to its material', 'It derives from the root kapar (to cover/atone), making the mercy seat literally the place of covering or atonement', 'It means "resting place" because the ark rested there', 'It derives from the word for "meeting"', 'a', 'Leviticus 16:14-15 — The kapporeth (mercy seat) derives from kapar, the same root as kippur in Yom Kippur. The sprinkling of blood on the mercy seat was the climactic act of atonement — God''s throne became the place of covering and forgiveness.'),
('Leviticus', 16, 'adults', 6, 'The Day of Atonement required Israel to "afflict your souls" (Leviticus 16:29). What did this phrase entail according to rabbinic tradition and broader biblical usage?', 'It meant to feel sad for one day', 'It meant fasting and self-denial, including abstaining from food, drink, and other bodily pleasures', 'It meant wearing sackcloth only', 'It meant confessing sins publicly to the priest', 'a', 'Leviticus 16:29 — "ye shall afflict your souls" (Hebrew: anah nefesh) refers to self-denial, primarily fasting. Isaiah 58:3-5 confirms this: "Wherefore have we fasted, say they...Behold, ye fast for strife." The day was a solemn Sabbath of rest and self-denial.'),
('Leviticus', 16, 'adults', 7, 'What happened to all the furnishings of the sanctuary and the altar on the Day of Atonement, and what does this reveal?', 'Only the ark was cleansed', 'The tabernacle, its furnishings, the altar, and the priesthood were all atoned for — the entire worship system needed annual purification', 'Only the people were atoned for, not the objects', 'The cleansing of the altar was done on a different day', 'a', 'Leviticus 16:16-20 — "he shall make an atonement for the holy place...And he shall make an atonement for the tabernacle of the congregation, and for the altar." The entire sacred space accumulated impurity from Israel''s sins and required annual cleansing — the whole covenant system needed renewal.'),
('Leviticus', 16, 'adults', 8, 'The two goats of the Day of Atonement have been identified typologically as representing two aspects of Christ''s atonement. What are these two aspects?', 'Justification and sanctification', 'Propitiation (the slain goat — satisfying God''s wrath) and expiation (the scapegoat — removing sin from the sinner)', 'The old covenant and the new covenant', 'Judgment and mercy as separate acts', 'a', 'Leviticus 16:15-22 — The slain goat, whose blood was brought into the Holy of Holies (v.15), pictures propitiation — satisfying divine justice. The scapegoat, bearing confessed sins into the wilderness (v.22), pictures expiation — the removal of sin''s guilt from the sinner. Christ''s one sacrifice accomplished both (Romans 3:25; Hebrews 9:26).');

-- ═══ Leviticus Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 17, 'kids', 1, 'Where were the Israelites required to bring their animals to be killed?', 'Anywhere in the camp', 'To the door of the tabernacle', 'Outside the camp in the wilderness', 'To the city gate', 'a', 'Leviticus 17:3-4 — "What man soever there be of the house of Israel, that killeth an ox, or lamb, or goat, in the camp, or that killeth it out of the camp, and bringeth it not unto the door of the tabernacle of the congregation, to offer an offering unto the LORD before the tabernacle of the LORD; blood shall be imputed unto that man."'),
('Leviticus', 17, 'kids', 2, 'What does the Bible say the life of the flesh is in?', 'The breath', 'The blood', 'The bones', 'The heart', 'a', 'Leviticus 17:11 — "For the life of the flesh is in the blood."'),
('Leviticus', 17, 'kids', 3, 'Were the Israelites allowed to eat blood?', 'Yes, in small amounts', 'No, it was completely forbidden', 'Only on feast days', 'Only the priests were forbidden', 'a', 'Leviticus 17:12 — "Therefore I said unto the children of Israel, No soul of you shall eat blood, neither shall any stranger that sojourneth among you eat blood."'),
-- Teens
('Leviticus', 17, 'teens', 1, 'What was the penalty for an Israelite who sacrificed an animal outside the tabernacle, even in the field?', 'He paid a fine to the priests', 'He was cut off from his people', 'He was given thirty lashes', 'He had to offer double at the tabernacle', 'a', 'Leviticus 17:4 — "blood shall be imputed unto that man; he hath shed blood; and that man shall be cut off from among his people."'),
('Leviticus', 17, 'teens', 2, 'Why did God forbid sacrifices "in the open field" apart from the tabernacle?', 'To prevent accidents in the field', 'To stop the Israelites from offering sacrifices to devils (goat idols, se''irim)', 'Because the ground in the field was unclean', 'So the priests could count all the animals', 'a', 'Leviticus 17:7 — "And they shall no more offer their sacrifices unto devils, after whom they have gone a whoring. This shall be a statute for ever unto them throughout their generations."'),
('Leviticus', 17, 'teens', 3, 'What reason does God give in Leviticus 17:11 for the blood being on the altar for atonement?', 'Because blood is valuable and should not be wasted', 'Because God has given the blood upon the altar to make atonement for souls, since the life is in the blood', 'Because blood purifies the altar', 'Because blood was a sign of the covenant with Abraham', 'a', 'Leviticus 17:11 — "For the life of the flesh is in the blood: and I have given it to you upon the altar to make an atonement for your souls: for it is the blood that maketh an atonement for the soul."'),
('Leviticus', 17, 'teens', 4, 'What were Israelites required to do if they killed an animal or bird while hunting?', 'Bring it to the tabernacle for inspection', 'Pour out its blood and cover it with dust', 'Give it to the priests', 'Offer it as a burnt offering', 'a', 'Leviticus 17:13 — "And whatsoever man there be of the children of Israel, or of the strangers that sojourn among you, which hunteth and catcheth any beast or fowl that may be eaten; he shall even pour out the blood thereof, and cover it with dust."'),
('Leviticus', 17, 'teens', 5, 'What was required of someone who ate an animal that died of itself or was torn by beasts?', 'They were put to death', 'They became unclean and had to wash their clothes and bathe, remaining unclean until evening', 'They had to offer a sin offering', 'They were cut off from Israel', 'a', 'Leviticus 17:15 — "And every soul that eateth that which died of itself, or that which was torn with beasts, whether it be one of your own country, or a stranger, he shall both wash his clothes, and bathe himself in water, and be unclean until the even: then shall he be clean."'),
-- Adults
('Leviticus', 17, 'adults', 1, 'The Hebrew word se''irim in Leviticus 17:7, translated "devils" in the KJV, literally means what?', 'Evil spirits in general', 'Hairy ones or goat-demons — a reference to goat-idol worship', 'Fallen angels', 'Foreign gods like Baal', 'a', 'Leviticus 17:7 — "they shall no more offer their sacrifices unto devils" (se''irim, hairy ones). This refers to goat idols or goat-demons, possibly related to the Canaanite worship Israel had adopted or been tempted to adopt in Egypt.'),
('Leviticus', 17, 'adults', 2, 'Leviticus 17:11 is a foundational text for understanding biblical atonement. What three things does it state about blood?', 'It is sacred, holy, and divine', 'The life of the flesh is in the blood; God has given it upon the altar; it makes atonement for the soul', 'It must be poured, burned, and buried', 'It is the sign of the covenant, the seal of the law, and the mark of Israel', 'a', 'Leviticus 17:11 — "For the life of the flesh is in the blood: and I have given it to you upon the altar to make an atonement for your souls: for it is the blood that maketh an atonement for the soul." These three clauses give the ontological basis (life is in blood), the divine authorisation (I have given it), and the soteriological function (it makes atonement).'),
('Leviticus', 17, 'adults', 3, 'How does Hebrews 9:22 quote the principle of Leviticus 17:11?', 'By saying the law of Moses was obsolete', '"Without shedding of blood is no remission"', '"The blood of bulls cannot cleanse the conscience"', '"Christ abolished the blood sacrifices"', 'a', 'Hebrews 9:22 — "And almost all things are by the law purged with blood; and without shedding of blood is no remission." This directly draws on Leviticus 17:11''s principle that the blood on the altar is the divinely appointed means of atonement.'),
('Leviticus', 17, 'adults', 4, 'The centralisation of sacrifice at the tabernacle in Leviticus 17 was temporary in what sense? What adjustment was made in Deuteronomy for the settlement in Canaan?', 'There was no adjustment; the law was permanent', 'Deuteronomy 12:15 permitted the slaughter of animals for food (not sacrifice) anywhere, while still requiring sacrificial offerings at the central sanctuary', 'Deuteronomy abolished all animal slaughter', 'Deuteronomy permitted sacrifice at any Levitical city', 'a', 'Leviticus 17:3-4 required all animal slaughter to be at the tabernacle — practical for the wilderness camp. Deuteronomy 12:15 modifies this for settled life: "thou mayest kill and eat flesh in all thy gates." The distinction between sacrificial and non-sacrificial slaughter was thus introduced as Israel spread across the land.'),
('Leviticus', 17, 'adults', 5, 'What is the scope of the blood prohibition in Leviticus 17 — did it apply only to Israelites?', 'Yes, only to native Israelites', 'No, it applied equally to strangers sojourning among Israel', 'Only to males over thirteen years of age', 'Only to those who had been circumcised', 'a', 'Leviticus 17:10 — "And whatsoever man there be of the house of Israel, or of the strangers that sojourn among you, that eateth any manner of blood; I will even set my face against that soul that eateth blood." The prohibition was universal within the covenant community, including resident aliens.'),
('Leviticus', 17, 'adults', 6, 'The Jerusalem Council in Acts 15 included "abstaining from blood" in its requirements for Gentile believers. How does this connect to Leviticus 17?', 'It has no connection to Leviticus 17', 'The council drew on the Noahide/sojourner provisions (cf. Leviticus 17:10) as a baseline for Gentile conduct in mixed Jewish-Gentile communities', 'The council rejected all of Leviticus''s food laws', 'It was only a temporary cultural accommodation', 'a', 'Acts 15:20 — "But that we write unto them, that they abstain from pollutions of idols, and from fornication, and from things strangled, and from blood." This parallels the Leviticus 17 provisions for sojourners, suggesting the council applied the sojourner ethic to Gentile believers in Jewish-majority communities.'),
('Leviticus', 17, 'adults', 7, 'What is the theological connection between the life being in the blood (Leviticus 17:11) and the Lord''s Supper in the New Testament?', 'There is no connection', 'Jesus''s words "This is my blood...shed for many for the remission of sins" (Matthew 26:28) consciously invoke the principle that life is in blood, presenting His blood as the ultimate atonement', 'The Lord''s Supper replaced the blood prohibition of Leviticus', 'Jesus''s words meant the grape juice was transformed into blood', 'a', 'Leviticus 17:11 — "it is the blood that maketh an atonement for the soul." Matthew 26:28 — "For this is my blood of the new testament, which is shed for many for the remission of sins." Jesus consciously invokes the Levitical principle: His blood, containing His life, is the final atoning sacrifice.'),
('Leviticus', 17, 'adults', 8, 'What does the covering of blood with dust after hunting (Leviticus 17:13) signify about the Israelite view of animal life?', 'It was a hygienic practice only', 'The blood, representing life, was returned to the earth from which life came — acknowledging God as the giver of all life and the owner of all blood', 'It was to hide the evidence of the kill', 'It was a form of offering to the earth', 'a', 'Leviticus 17:13-14 — "he shall...pour out the blood thereof, and cover it with dust. For it is the life of all flesh; the blood of it is for the life thereof." The act of covering blood with dust acknowledged that the life belonged to God and was being returned to His creation, not casually discarded.');

-- ═══ Leviticus Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 18, 'kids', 1, 'Whose ways were the Israelites told NOT to follow at the start of Leviticus 18?', 'The Philistines'' and Moabites'' ways', 'The Egyptians'' and Canaanites'' ways', 'The Babylonians'' and Assyrians'' ways', 'The Midianites'' and Edomites'' ways', 'a', 'Leviticus 18:3 — "After the doings of the land of Egypt, wherein ye dwelt, shall ye not do: and after the doings of the land of Canaan, whither I bring you, shall ye not do: neither shall ye walk in their ordinances."'),
('Leviticus', 18, 'kids', 2, 'Was it allowed to give your children to Molech?', 'Yes, if the priest approved', 'No, it was absolutely forbidden', 'Only in times of great danger', 'Only the firstborn could be given', 'a', 'Leviticus 18:21 — "And thou shalt not let any of thy seed pass through the fire to Molech, neither shalt thou profane the name of thy God: I am the LORD."'),
('Leviticus', 18, 'kids', 3, 'What does God say the land would do if the people broke all these laws?', 'The land would catch fire', 'The land would vomit them out', 'The land would dry up', 'The land would be flooded', 'a', 'Leviticus 18:28 — "That the land spue not you out also, when ye defile it, as it spued out the nations that were before you."'),
-- Teens
('Leviticus', 18, 'teens', 1, 'What was the repeated phrase God used to introduce the laws in Leviticus 18 and throughout the chapter?', '"Thus saith Moses"', '"I am the LORD your God"', '"Hear, O Israel"', '"The LORD thy God commands thee"', 'a', 'Leviticus 18:2 — "Speak unto the children of Israel, and say unto them, I am the LORD your God." This divine self-identification (repeated in vv. 4, 5, 6, 21, 30) grounds all the laws in the identity and authority of God.'),
('Leviticus', 18, 'teens', 2, 'What does Leviticus 18:5 say about the man who keeps God''s statutes and judgments?', '"He will be blessed in the land"', '"He shall live in them"', '"He will find peace with God"', '"He shall receive great reward"', 'a', 'Leviticus 18:5 — "Ye shall therefore keep my statutes, and my judgments: which if a man do, he shall live in them: I am the LORD."'),
('Leviticus', 18, 'teens', 3, 'Leviticus 18 lists many forbidden sexual relations. What is the general term used for these forbidden relationships?', 'Abominations', 'Uncovering nakedness', 'Walking in the ordinances of the Canaanites', 'Defiling the land', 'a', 'Leviticus 18:6 — "None of you shall approach to any that is near of kin to him, to uncover their nakedness: I am the LORD." The phrase "uncover nakedness" is the technical term used throughout the chapter for these sexual unions.'),
('Leviticus', 18, 'teens', 4, 'Why does God say the Canaanites were being driven out of the land?', 'Because they were too numerous', 'Because they had committed all these abominations and defiled the land', 'Because God had promised the land to Abraham only', 'Because they had refused to keep the Sabbath', 'a', 'Leviticus 18:24-25 — "Defile not ye yourselves in any of these things: for in all these the nations are defiled which I cast out before you: and the land is defiled: therefore I do visit the iniquity thereof upon it."'),
('Leviticus', 18, 'teens', 5, 'What is the word used in Leviticus 18 to describe same-sex relations and relations with animals?', 'Sin', 'Abomination and confusion', 'Unclean', 'Transgression', 'a', 'Leviticus 18:22-23 — "Thou shalt not lie with mankind, as with womankind: it is abomination. Neither shalt thou lie with any beast to defile thyself therewith: neither shall any woman stand before a beast to lie down thereto: it is confusion."'),
-- Adults
('Leviticus', 18, 'adults', 1, 'Leviticus 18:5 — "He shall live in them" — is quoted twice in the New Testament. By whom and in what context?', 'By Peter and John', 'By Paul in Romans 10:5 and Galatians 3:12, contrasting law-keeping as a means of life with faith', 'By Jesus in the Sermon on the Mount', 'By the writer of Hebrews', 'a', 'Romans 10:5 — "Moses describeth the righteousness which is of the law, That the man which doeth those things shall live by them." Galatians 3:12 — "And the law is not of faith: but, The man that doeth them shall live in them." Paul cites Leviticus 18:5 to argue that law-righteousness and faith-righteousness are distinct principles.'),
('Leviticus', 18, 'adults', 2, 'What is the significance of the phrase "I am the LORD" appearing six times in Leviticus 18?', 'It is a liturgical refrain with no specific significance', 'It anchors every prohibition in the covenant character of God — these are not arbitrary cultural rules but expressions of divine holiness', 'It identifies each law as a separate commandment', 'It signals that each law is more important than the previous one', 'a', 'The sevenfold repetition of "I am the LORD" (vv.2,4,5,6,21,30) grounds the sexual ethics of Leviticus 18 not in natural law alone but in the personal identity of the God who redeemed Israel from Egypt and entered into covenant with them.'),
('Leviticus', 18, 'adults', 3, 'The prohibition against giving seed to Molech (Leviticus 18:21) appears in the middle of sexual prohibitions. What connection does this placement suggest?', 'It is out of place and should be in another chapter', 'Child sacrifice was connected to the same realm of violations against God''s gift of life and family — both sexual sin and Molech worship destroyed the seed and household God intended to be holy', 'It is an insertion from a different source', 'It only relates to agricultural seed, not children', 'a', 'Leviticus 18:21 — The placement of the Molech prohibition within the sexual ethics section links the gift of progeny (seed) to God''s purposes. To give seed to Molech was to destroy life God had given, violating both the sanctity of human life and the name of God ("neither shalt thou profane the name of thy God").'),
('Leviticus', 18, 'adults', 4, 'What does the metaphor of the land "vomiting out" its inhabitants (Leviticus 18:25,28) communicate theologically?', 'The land was populated by demons who rejected people', 'Sexual and religious sins were so fundamentally disordering that even the created order (the land) was treated as rejecting those who violated God''s ordinances', 'It was a figure of speech with no literal meaning', 'It referred to volcanic activity in Canaan', 'a', 'Leviticus 18:25 — "And the land is defiled: therefore I do visit the iniquity thereof upon it, and the land itself vomiteth out her inhabitants." The metaphor personifies the land as sickened by moral pollution, reflecting the Hebrew understanding that creation itself was ordered by God''s law and experienced disorder when that law was violated.'),
('Leviticus', 18, 'adults', 5, 'Leviticus 18 begins by rejecting both Egyptian and Canaanite practices. What does this double rejection reveal about the nature of the laws?', 'Israel had already adopted Egyptian practices that needed correction', 'The laws define a unique covenant identity — Israel was not to conform to the culture they left or the culture they were entering', 'The laws were negotiated between Moses and the Egyptians', 'Only Canaanite practices were truly sinful', 'a', 'Leviticus 18:3 — "After the doings of the land of Egypt...shall ye not do: and after the doings of the land of Canaan...shall ye not do." By naming both civilisations, God constitutes Israel as a third way — a holy nation whose ethics are derived from His character, not from cultural context.'),
('Leviticus', 18, 'adults', 6, 'The incest prohibitions in Leviticus 18:7-18 cover many degrees of relationship. What structural principle organises these prohibitions?', 'They are listed randomly', 'They move outward from the closest nuclear family (parents) to extended family (aunt, sister-in-law), using "uncover the nakedness of" as the consistent legal phrase', 'They list only female relatives', 'They are organised alphabetically in Hebrew', 'a', 'Leviticus 18:7-18 moves systematically: mother (v.7), father''s other wife (v.8), full/half sister (vv.9,11), granddaughter (v.10), father''s sister (v.12), mother''s sister (v.13), father''s brother''s wife (v.14), daughter-in-law (v.15), brother''s wife (v.16), woman and her daughter (v.17), wife''s sister as rival wife (v.18). The consistent phrase "uncover nakedness" structures each case.'),
('Leviticus', 18, 'adults', 7, 'Paul''s condemnation of sexual immorality in 1 Corinthians 5:1 references a specific case of incest. How does this relate to Leviticus 18?', 'Paul invented this prohibition without reference to the law', 'Paul condemns a man who has his father''s wife, exactly the case prohibited in Leviticus 18:8, noting it was "not so much as named among the Gentiles"', 'Paul cited this as an example of the law being abolished', 'Paul was addressing a unique situation not found in the law', 'a', '1 Corinthians 5:1 — "It is reported commonly that there is fornication among you...that one should have his father''s wife." This precisely matches Leviticus 18:8 — "The nakedness of thy father''s wife shalt thou not uncover: it is thy father''s nakedness." Paul''s moral reasoning draws directly on the Levitical framework.'),
('Leviticus', 18, 'adults', 8, 'How does Leviticus 18:24-25 function as a theological explanation for the conquest of Canaan?', 'It presents the conquest as ethnic cleansing with no moral justification', 'It frames the expulsion of the Canaanites as divine judgment for specific enumerated sins, not ethnic preference, making the conquest a morally coherent act of justice', 'It suggests the Canaanites were expelled for racial reasons', 'It is only a warning to Israel with no reference to Canaan''s fate', 'a', 'Leviticus 18:24-25 — "Defile not ye yourselves...for in all these the nations are defiled which I cast out before you: and the land is defiled: therefore I do visit the iniquity thereof upon it." The text makes explicit that Canaan''s expulsion was moral judgment for the sins catalogued in vv.6-23 — the same sins now forbidden to Israel. The conquest is thus presented as judicial, not arbitrary.');

-- ═══ Leviticus Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 19, 'kids', 1, 'What command did God give to Israel at the very beginning of Leviticus 19?', '"Obey all my laws"', '"Ye shall be holy: for I the LORD your God am holy"', '"Build a temple for me"', '"Fear no man"', 'a', 'Leviticus 19:2 — "Speak unto all the congregation of the children of Israel, and say unto them, Ye shall be holy: for I the LORD your God am holy."'),
('Leviticus', 19, 'kids', 2, 'What were farmers commanded to leave in their fields for the poor?', 'Half of the harvest', 'The corners of the field and the gleanings for the poor and stranger', 'One row of grain', 'The last basket of fruit', 'a', 'Leviticus 19:9-10 — "And when ye reap the harvest of your land, thou shalt not wholly reap the corners of thy field, neither shalt thou gather the gleanings of thy harvest...thou shalt leave them for the poor and stranger: I am the LORD your God."'),
('Leviticus', 19, 'kids', 3, 'What is the great commandment about neighbours that Jesus later called the second great commandment?', '"Be kind to your neighbours"', '"Thou shalt love thy neighbour as thyself"', '"Do not harm your neighbour"', '"Help your neighbour in need"', 'a', 'Leviticus 19:18 — "Thou shalt not avenge, nor bear any grudge against the children of thy people, but thou shalt love thy neighbour as thyself: I am the LORD."'),
-- Teens
('Leviticus', 19, 'teens', 1, 'Leviticus 19 lists many practical holiness laws. Which of the following is commanded in this chapter?', '"Thou shalt make no idols"', '"Thou shalt rise up before the hoary head, and honour the face of the old man"', '"Thou shalt not eat of the fat of the animal"', '"Thou shalt offer a burnt offering on the Sabbath"', 'a', 'Leviticus 19:32 — "Thou shalt rise up before the hoary head, and honour the face of the old man, and fear thy God: I am the LORD."'),
('Leviticus', 19, 'teens', 2, 'What does Leviticus 19 command about dealing with the deaf and blind?', '"Teach them and care for them"', '"Thou shalt not curse the deaf, nor put a stumblingblock before the blind"', '"Build them a safe place in the camp"', '"Appoint Levites to care for them"', 'a', 'Leviticus 19:14 — "Thou shalt not curse the deaf, nor put a stumblingblock before the blind, but shalt fear thy God: I am the LORD."'),
('Leviticus', 19, 'teens', 3, 'What does Leviticus 19:15 command about justice in judgment?', '"Favour the poor because they are needy"', '"Thou shalt not do unrighteousness in judgment: thou shalt not respect the person of the poor, nor honour the person of the mighty; but in righteousness shalt thou judge thy neighbour"', '"Let the priest decide all cases"', '"Give the benefit of the doubt to the rich"', 'a', 'Leviticus 19:15 — "Ye shall do no unrighteousness in judgment: thou shalt not respect the person of the poor, nor honour the person of the mighty: but in righteousness shalt thou judge thy neighbour."'),
('Leviticus', 19, 'teens', 4, 'What does Leviticus 19 say about mixing two kinds of seed, wearing garments of mixed linen and wool, or plowing with two different animals?', 'These were encouraged as signs of diversity', 'These were all forbidden as diverse kinds (sha''atnez)', 'Only wearing mixed cloth was forbidden', 'These were customs from Egypt to be avoided', 'a', 'Leviticus 19:19 — "Thou shalt not let thy cattle gender with a diverse kind: thou shalt not sow thy field with mingled seed: neither shall a garment mingled of linen and woollen come upon thee."'),
('Leviticus', 19, 'teens', 5, 'What law about the stranger is given in Leviticus 19:33-34?', '"Be polite to strangers but do not eat with them"', '"The stranger that dwelleth with you shall be as one born among you, and thou shalt love him as thyself"', '"Strangers must follow only the food laws"', '"Test strangers before welcoming them"', 'a', 'Leviticus 19:34 — "But the stranger that dwelleth with you shall be unto you as one born among you, and thou shalt love him as thyself; for ye were strangers in the land of Egypt: I am the LORD your God."'),
-- Adults
('Leviticus', 19, 'adults', 1, 'Leviticus 19:18 contains the command to love one''s neighbour as oneself. How did Jesus use this verse in the New Testament?', 'He quoted it as the least of the commandments', 'He declared it the second great commandment, equal to loving God, and said all the law and prophets hang on these two', 'He said it was only for Israel, not for Gentiles', 'He replaced it with a new commandment', 'a', 'Matthew 22:39 — "And the second is like unto it, Thou shalt love thy neighbour as thyself." Matthew 22:40 — "On these two commandments hang all the law and the prophets." Jesus directly cites Leviticus 19:18 and elevates it to the heart of the entire Mosaic ethic.'),
('Leviticus', 19, 'adults', 2, 'The phrase "I am the LORD" appears approximately fifteen times in Leviticus 19. What is the rhetorical and theological function of this repetition?', 'It is a scribal error repeated through copying', 'Each law is individually grounded in the covenant identity of God — obedience is not to an abstract code but to the personal God who redeemed Israel', 'It marks the laws that were specifically for priests', 'It indicates which laws could be modified by Israel''s leaders', 'a', 'Leviticus 19:2-37 — The repeated "I am the LORD" (approximately 15 occurrences) does not mark a section heading but closes each individual law or cluster with a divine claim. This personalises the law, making each statute a direct expression of the character of the God who says "I am the LORD."'),
('Leviticus', 19, 'adults', 3, 'What is the sha''atnez law (Leviticus 19:19; Deuteronomy 22:11) and how has it been interpreted theologically?', 'It is a law against wearing too many layers of clothing', 'The prohibition of mixing wool and linen has been interpreted as a holiness boundary — maintaining the distinctions God created, or as reserving the priestly garments (which combined both) for their unique sacred function', 'It was purely a health code against skin irritation', 'It was borrowed from Egyptian customs', 'a', 'Leviticus 19:19 — "neither shall a garment mingled of linen and woollen come upon thee." Deuteronomy 22:11 — "Thou shalt not wear a garment of divers sorts, as of woollen and linen together." Priestly garments combined linen and wool (Exodus 28:6,8,15), so one interpretation is that the prohibition reserved this mixture for the holy priesthood, maintaining boundaries between the sacred and common.'),
('Leviticus', 19, 'adults', 4, 'Leviticus 19:26-28 prohibits divination, enchantment, rounding the corners of the head, and cutting marks in the flesh. What do these prohibitions have in common?', 'They are arbitrary cultural restrictions', 'They are practices associated with pagan mourning rites and occult communication — all were forms of seeking knowledge or power outside the covenant with God', 'They were forbidden for hygienic reasons', 'They were practices Moses personally disliked', 'a', 'Leviticus 19:26-28 — "Ye shall not eat any thing with the blood: neither shall ye use enchantment, nor observe times...Ye shall not make any cuttings in your flesh for the dead, nor print any marks upon you." These practices were associated with communication with the dead, seeking occult wisdom, and pagan mourning rituals — all violations of exclusive covenant fidelity to God.'),
('Leviticus', 19, 'adults', 5, 'The gleaning laws (Leviticus 19:9-10) are illustrated in the book of Ruth. What theological principle do they embody?', 'Charity was optional in Israel', 'The produce of the land ultimately belonged to God; Israel''s ownership was stewardship, and the poor had a God-given right to a portion of the harvest', 'The gleaning laws were only for Levites', 'Poor people were required to work before receiving any food', 'a', 'Leviticus 19:9-10 — "thou shalt leave them for the poor and stranger: I am the LORD your God." The gleaning laws embedded the rights of the poor into the agricultural economy, reflecting the principle that the land and its produce belonged to God (Leviticus 25:23) and were held in trust for all members of the covenant community.'),
('Leviticus', 19, 'adults', 6, 'What is the Orla law in Leviticus 19:23-25 and what does it teach about patience and covenant faithfulness?', 'The law against eating the first grain after the Sabbath', 'The law forbidding eating the fruit of newly planted trees for three years; the fourth year fruit was holy to the LORD; only in the fifth year was it for personal use', 'The law against cutting down fruit trees in war', 'The law about planting on the Sabbath year', 'a', 'Leviticus 19:23-25 — "And when ye shall come into the land, and shall have planted all manner of trees for food...three years shall it be as uncircumcised unto you...in the fourth year all the fruit thereof shall be holy to praise the LORD...and in the fifth year shall ye eat of the fruit thereof." The Orla law taught Israel to wait, surrender the first increase to God, and trust His provision.'),
('Leviticus', 19, 'adults', 7, 'How does Leviticus 19:17-18 present the internal heart requirement of the law, in contrast to merely external behaviour?', 'It only regulates external actions', '"Thou shalt not hate thy brother in thine heart" (v.17) addresses the interior disposition, making hatred and grudge-bearing violations of the law alongside outward acts', 'It only concerns the treatment of enemies', 'The verse is only about community dispute resolution', 'a', 'Leviticus 19:17-18 — "Thou shalt not hate thy brother in thine heart...thou shalt not avenge, nor bear any grudge...but thou shalt love thy neighbour as thyself." The law reaches into the heart (hatred, grudges) not merely external behaviour, anticipating Jesus''s Sermon on the Mount (Matthew 5:21-22) in demanding interior righteousness.'),
('Leviticus', 19, 'adults', 8, 'James 2:8 calls the command to love one''s neighbour "the royal law." How does this designation connect to Leviticus 19:18 and the overall argument of James?', 'James uses it as an example of a law that can be broken without consequence', 'By calling it the "royal law," James elevates Leviticus 19:18 as the kingly standard by which all social behaviour is judged — showing partiality violates this royal law and makes one a transgressor', 'James argues this law replaced all of Leviticus', 'James uses the phrase "royal law" to mean a law only for kings', 'a', 'James 2:8 — "If ye fulfil the royal law according to the scripture, Thou shalt love thy neighbour as thyself, ye do well." James argues that showing partiality to the rich (James 2:1-4) violates this royal law of Leviticus 19:18, demonstrating that the Levitical ethics remained normative for the New Testament church.');

-- ═══ Leviticus Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 20, 'kids', 1, 'What was the punishment for anyone who gave their children to the false god Molech?', 'They were sent out of the camp', 'They were put to death', 'They had to pay a large offering', 'They were made to be servants', 'a', 'Leviticus 20:2 — "Whosoever he be of the children of Israel, or of the strangers that sojourn in Israel, that giveth any of his seed unto Molech; he shall surely be put to death: the people of the land shall stone him with stones."'),
('Leviticus', 20, 'kids', 2, 'What was God''s punishment for someone who went to a medium or wizard?', 'He would bless them with much less', 'God would set His face against that person and cut them off', 'They had to bring a special offering', 'They lost their firstborn child', 'a', 'Leviticus 20:6 — "And the soul that turneth after such as have familiar spirits, and after wizards, to go a whoring after them, I will even set my face against that soul, and will cut him off from among his people."'),
('Leviticus', 20, 'kids', 3, 'What does God say He has done to separate Israel from other peoples?', 'He gave Israel more land', 'He has severed them from other people that they should be His', 'He gave them more laws to follow', 'He made them stronger than all nations', 'a', 'Leviticus 20:26 — "And ye shall be holy unto me: for I the LORD am holy, and have severed you from other people, that ye should be mine."'),
-- Teens
('Leviticus', 20, 'teens', 1, 'If the community of Israel looked the other way and did nothing when a man gave his child to Molech, what did God say He would do?', 'Nothing, since the community was innocent', 'He would set His face against that man and his family and cut them off', 'He would send a plague on the community', 'He would raise up enemies against Israel', 'a', 'Leviticus 20:4-5 — "And if the people of the land do any ways hide their eyes from the man, when he giveth of his seed unto Molech, and kill him not: then I will set my face against that man, and against his family, and will cut him off."'),
('Leviticus', 20, 'teens', 2, 'What was the punishment for cursing one''s father or mother according to Leviticus 20?', 'They were beaten and made to apologise', 'His blood shall be upon him — they were put to death', 'They were exiled for thirty days', 'They lost their inheritance', 'a', 'Leviticus 20:9 — "For every one that curseth his father or his mother shall be surely put to death: he hath cursed his father or his mother; his blood shall be upon him."'),
('Leviticus', 20, 'teens', 3, 'What phrase does Leviticus 20 repeatedly use for sins committed between people, indicating personal accountability?', '"Their iniquity be upon them"', '"His blood shall be upon him" / "they shall bear their iniquity"', '"The LORD will judge them"', '"Let them be cast out of the assembly"', 'a', 'Leviticus 20:9,11,12,13,16 etc. — The repeated phrases "his blood shall be upon him" and "they shall bear their iniquity" emphasise that those who commit these sins take personal responsibility for the consequences of their actions.'),
('Leviticus', 20, 'teens', 4, 'What distinguished the clean and unclean animals, and why does Leviticus 20 mention this again at the end of the chapter?', 'To add detail to the dietary laws', 'God had severed Israel from the nations just as He had severed clean from unclean animals — the distinctions of diet reflected the holy/common distinction of Israel''s identity', 'The dietary laws were being updated in this chapter', 'It was a summary for new Israelites joining the community', 'a', 'Leviticus 20:24-26 — "I am the LORD your God, which have separated you from other people...Ye shall therefore put difference between clean beasts and unclean...and ye shall be holy unto me: for I the LORD am holy, and have severed you from other people, that ye should be mine." The dietary distinctions mirror the theological distinction of Israel''s election.'),
('Leviticus', 20, 'teens', 5, 'What was the fate of anyone in Israel who was a medium or wizard?', 'They were expelled from the camp', 'They were put to death by stoning', 'They were placed under the authority of the priests', 'They were given one chance to repent', 'a', 'Leviticus 20:27 — "A man also or woman that hath a familiar spirit, or that is a wizard, shall surely be put to death: they shall stone them with stones: their blood shall be upon them."'),
-- Adults
('Leviticus', 20, 'adults', 1, 'The phrase "I will set my face against" appears in Leviticus 20:3,5,6. What is the covenantal weight of this phrase?', 'It is a mild expression of disappointment', 'It is the most severe expression of divine opposition — God''s active, personal, covenant-breaking hostility against the offender', 'It means God will watch them more closely', 'It refers to God turning away without acting', 'a', 'Leviticus 20:3 — "I will set my face against that man." This phrase (natan panim b-) is the inverse of the Aaronic blessing''s "the LORD make his face shine upon thee" (Numbers 6:25) — it represents the full weight of divine covenantal hostility, the opposite of blessing and presence.'),
('Leviticus', 20, 'adults', 2, 'Leviticus 20 applies the death penalty to a range of offences. What principle guided the severity of penalties, and how were gradations of punishment distinguished?', 'All offences received equal punishment', 'Offences were graded from death (the most severe violations of covenant fundamentals) to being cut off to bearing iniquity without community-administered penalty', 'The penalties were arbitrary', 'The priests decided each case individually', 'a', 'Leviticus 20 has three tiers: (1) death sentences (vv.2,9,10,11,12,13,15,16,27) for the gravest covenant violations; (2) being "cut off" (vv.17,18) indicating divine removal without community action; (3) "bearing iniquity" (vv.17,19,20) leaving accountability with God. This graduated system reflects proportional justice.'),
('Leviticus', 20, 'adults', 3, 'Leviticus 20:17 — the case of a man seeing the nakedness of his sister and both bearing their iniquity — does not prescribe death but being "cut off in the sight of their people." What does being "cut off" (karet) mean in Hebrew law?', 'Banishment from the camp for thirty days', 'Excommunication from the covenant community, possibly including divine judgment of premature death', 'Having the right hand cut off as punishment', 'Loss of inheritance rights only', 'a', 'The Hebrew karet (cut off) in Leviticus 20:17-18 refers to exclusion from the covenant community. Rabbinic tradition understood it as premature death by divine action when no human court acted. It represents removal from God''s covenant blessings, a form of covenantal death.'),
('Leviticus', 20, 'adults', 4, 'How does the command of Leviticus 20:26 — "I have severed you from other people, that ye should be mine" — function as the theological capstone of Leviticus 18-20?', 'It is a postscript with no connection to the preceding laws', 'It reveals that the entire holiness code of chapters 18-20 is grounded in Israel''s election — their holiness is a response to their identity as God''s separated people', 'It refers only to dietary laws', 'It addresses only Israel''s relationship to Egypt', 'a', 'Leviticus 20:26 — The word "severed" (badal) echoes the separation of light from darkness in Genesis 1:4 and the division of clean from unclean in Leviticus 20:25. Israel''s election (severed from nations) is the basis and pattern for their ethical distinctiveness — they are holy because God is holy and has made them His own.'),
('Leviticus', 20, 'adults', 5, 'The reference to the land flowing with milk and honey in Leviticus 20:24 appears in the context of the laws of holiness. What theological point does this juxtaposition make?', 'The land was the reward for keeping the dietary laws only', 'Blessing in the land (milk and honey) was inseparable from covenantal faithfulness — the land''s abundance depended on Israel''s holiness', 'The description of the land was to motivate keeping only the purity laws', 'It is a geographical note irrelevant to the laws', 'a', 'Leviticus 20:24 — "I am the LORD your God, which have separated you from other people...I have said unto you, Ye shall inherit their land, a land that floweth with milk and honey." The promise of the land is embedded within the holiness commands, making clear that retention of the land was tied to covenantal obedience (cf. Leviticus 18:28).'),
('Leviticus', 20, 'adults', 6, 'Paul quotes from Leviticus 20:26 in 2 Corinthians 6:17 — "come out from among them, and be ye separate, saith the Lord." How does this New Testament use recontextualise the Leviticus 20 principle?', 'Paul argues Israel''s separation laws are now irrelevant', 'Paul applies the principle of separation from the nations to the call of believers to be distinct from the world — the election-holiness principle of Leviticus is reapplied to the new covenant community', 'Paul is only addressing dietary laws', 'Paul uses it as a proof text for physical isolation from non-believers', 'a', '2 Corinthians 6:17 — "Come out from among them, and be ye separate, saith the Lord, and touch not the unclean thing." Paul draws on Leviticus 20:26''s principle of separation as belonging to God and applies it to the new covenant community''s ethical distinctiveness in a Gentile world, showing the Levitical holiness principle transcends its original form.'),
('Leviticus', 20, 'adults', 7, 'The death penalty for adultery in Leviticus 20:10 applied to both parties — "the man that committeth adultery with another man''s wife." What does this symmetrical application reveal about the law?', 'The law was biased toward women', 'The law applied equally to both the man and the woman involved, reflecting an even-handed justice rather than holding only one party accountable', 'Only the woman was truly at fault', 'The penalty was rarely enforced', 'a', 'Leviticus 20:10 — "the man that committeth adultery with another man''s wife...the adulterer and the adulteress shall surely be put to death." The equal accountability of both parties stands in contrast to ancient Near Eastern laws that often punished women more severely, reflecting a principle of equal moral responsibility before God.'),
('Leviticus', 20, 'adults', 8, 'Leviticus 20 ends with the command regarding mediums and wizards (v.27). How does this final verse bring Leviticus 17-20 to a thematic close?', 'It adds a new topic unrelated to the preceding material', 'It completes the holiness code''s treatment of all rival allegiances — sexual, familial, and spiritual — by closing with the prohibition of occult consultation, which was the ultimate rival to seeking God', 'It begins a new section on priesthood', 'It refers only to Canaanite priests', 'a', 'Leviticus 20:27 — The final verse on mediums and wizards echoes the opening concern of Leviticus 20 (Molech worship, v.2) and Leviticus 19:31 — "Regard not them that have familiar spirits, neither seek after wizards, to be defiled by them." Together, chapters 17-20 form the Holiness Code''s comprehensive vision: Israel''s loyalty to God must be total — in sacrifice (17), sexuality (18), ethics (19), and spirituality (20).');
